mapper.select:
select r.*,
       m.name as member_name,
       m.phone as member_phone,
       d.dept_name
from member_card_refund_order r
left join member m on r.member_id = m.id
left join sys_dept d on r.dept_id = d.dept_id

    r.is_del = 0
    and r.refund_order_no like concat('%', #{refundOrderNo}, '%')
    and r.sale_order_no like concat('%', #{saleOrderNo}, '%')
    and r.member_card_id = #{memberCardId}
    and r.member_id = #{memberId}
    and r.member_no like concat('%', #{memberNo}, '%')
    and m.name like concat('%', #{memberNameLike}, '%')
    and m.phone like concat('%', #{memberPhone}, '%')
    and r.card_type_id = #{cardTypeId}
    and r.card_type_name like concat('%', #{cardTypeName}, '%')
    and r.refund_type = #{refundType}
    and r.refund_status = #{refundStatus}
    and r.dept_id = #{deptId}
    and r.operator_name like concat('%', #{operatorName}, '%')
    and r.refund_time >= #{beginRefundTime}
    and r.refund_time <= #{endRefundTime}
    and r.created_at >= #{beginCreatedAt}
    and r.created_at <= #{endCreatedAt}
    ${params.dataScope}

order by r.refund_time desc, r.created_at desc, r.id desc
